const texto = $('Extraer Datos Mensaje').item.json.texto.trim();
const telegram_user = $json.telegram_user;
let opcion = null;
if (texto === '1') opcion = 'solicitar';
else if (texto === '2') opcion = 'consultar';
else if (texto === '3') opcion = 'cancelar';
return [{ json: { opcion, telegram_user } }];

const items = $input.all().map(i => i.json);
const telegram_user = $('Interpretar Opcion Menu').first().json.telegram_user;
let texto;
if (items.length === 0) {
  texto = 'No tienes tutorias registradas todavia.';
} else {
  texto = 'Tus tutorias:\n' + items.map(t => '- ' + t.materia + ' | ' + t.fecha + ' ' + t.hora + ' | Estado: ' + t.estado).join('\n');
}
return [{ json: { texto, telegram_user } }];

const items = $input.all().map(i => i.json).filter(t => t.estado === 'Asignada' || t.estado === 'Confirmada');
const telegram_user = $('Interpretar Opcion Menu').first().json.telegram_user;
let texto, hay;
if (items.length === 0) {
  texto = 'No tienes tutorias activas para cancelar.'; hay = false;
} else {
  texto = 'Cual quieres cancelar? Responde con el numero:\n' + items.map((t,i) => (i+1) + '. ' + t.materia + ' | ' + t.fecha + ' ' + t.hora).join('\n');
  hay = true;
}
return [{ json: { texto, hay, lista: JSON.stringify(items), telegram_user } }];

const MATERIAS = {'1':'Matematicas','2':'Lengua castellana','3':'Filosofia','4':'Fisica','5':'Quimica'};
const texto = $('Extraer Datos Mensaje').item.json.texto.trim();
const materia = MATERIAS[texto];
return [{ json: { valido: !!materia, materia: materia || null, telegram_user: $('Extraer Datos Mensaje').item.json.telegram_user } }];

const texto = $('Extraer Datos Mensaje').item.json.texto.trim();
const regex = /^\d{4}-\d{2}-\d{2}$/;
let valido = regex.test(texto);
let fechaObj = null;
if (valido) {
  fechaObj = new Date(texto + 'T00:00:00');
  const hoy = new Date(); hoy.setHours(0,0,0,0);
  if (isNaN(fechaObj.getTime()) || fechaObj < hoy) valido = false;
}
const dias = ['Domingo','Lunes','Martes','Miercoles','Jueves','Viernes','Sabado'];
const datosParciales = JSON.parse($json.datos_parciales || '{}');
return [{ json: { valido, fecha: texto, dia_semana: valido ? dias[fechaObj.getDay()] : null, materia: datosParciales.materia, telegram_user: $json.telegram_user }}];

const disponibilidad = $('Leer Disponibilidad').all().map(i => i.json);
const tutores = $input.all().map(i => i.json);
const ctx = $('Validar Fecha').first().json;
const materia = ctx.materia;
const matches = [];
for (const d of disponibilidad) {
  const tutor = tutores.find(t => t.id_tutor === d.id_tutor && (t.especialidad_materias || '').split(',').map(s => s.trim()).includes(materia));
  if (tutor) matches.push({ id_dispo: d.id_dispo, id_tutor: tutor.id_tutor, nombre_tutor: tutor.nombre, hora_inicio: d.hora_inicio, hora_fin: d.hora_fin });
}
let texto;
if (matches.length === 0) texto = 'No hay tutores libres de ' + materia + ' ese dia. Intenta otra fecha.';
else texto = 'Opciones para ' + materia + ':\n' + matches.map((m,i) => (i+1)+'. '+m.nombre_tutor+' ('+m.hora_inicio+'-'+m.hora_fin+')').join('\n') + '\n\nResponde con el numero.';
return [{ json: { hay_opciones: matches.length > 0, texto_respuesta: texto, opciones: JSON.stringify(matches), materia, fecha: ctx.fecha, telegram_user: ctx.telegram_user }}];

const texto = $('Extraer Datos Mensaje').item.json.texto.trim();
const datosParciales = JSON.parse($json.datos_parciales || '{}');
const opciones = JSON.parse(datosParciales.opciones || '[]');
const idx = parseInt(texto, 10) - 1;
const elegida = opciones[idx];
return [{ json: { valido: !!elegida, elegida: elegida || null, materia: datosParciales.materia, fecha: datosParciales.fecha, telegram_user: $json.telegram_user }}];

const texto = $('Extraer Datos Mensaje').item.json.texto.trim();
const datosParciales = JSON.parse($json.datos_parciales || '{}');
const lista = JSON.parse(datosParciales.lista || '[]');
const idx = parseInt(texto, 10) - 1;
const elegida = lista[idx];
return [{ json: { valido: !!elegida, elegida: elegida || null, telegram_user: $json.telegram_user }}];

const texto = $('Extraer Datos Mensaje').item.json.texto.trim();
const disponibilidad = $json.disponibilidad;
let opcion = null;
if (texto === '1') opcion = 'descuenta';
else if (texto === '2') opcion = 'actualiza';
return [{ json: { opcion, disponibilidad } }];
